3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
18	const CURSED_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	function loyaltyDiscountFor(yearsInsured: number, baseTotal: number): number {
26	  return yearsInsured >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
27	}
28	
29	function followUpDiscountFor(contractNumber: number, baseTotal: number): number {
30	  return contractNumber > 1 ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
31	}
32	
33	function withFirstInsurance(basePremium: number): number {
34	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
35	}
36	
37	function premiumForTypeGroup(type: string, count: number): number {
38	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
39	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
40	  }
41	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
42	}
43	
44	type Item = { type: string; cursed?: boolean; enchantment?: number };
45	
46	function surchargeRateForItem(item: Item): number {
47	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
48	  const enchantmentRate =
49	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
50	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
51	      : 0;
52	  return cursedRate + enchantmentRate;
53	}
54	
55	function surchargeForItem(item: Item): number {
56	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
57	}
58	
59	const CLAIM_DEDUCTIBLE = 100;
60	const CAP_MULTIPLIER = 2;
61	const REDUCED_REIMBURSEMENT_RATE = 0.5;
62	const REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
63	
64	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
65	  sword: 1000,
66	  amulet: 600,
67	  staff: 800,
68	  potion: 400,
69	  rune: 250,
70	  moonstone: 250,
71	};
72	
73	type Damage = { type: string; amount: number };
74	
75	function insuranceCapFor(items: Item[]): number {
76	  const insuranceSum = items.reduce(
77	    (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
78	    0,
79	  );
80	  return insuranceSum * CAP_MULTIPLIER;
81	}
82	
83	function hasReducedReimbursement(item: Item): boolean {
84	  return (item.enchantment ?? 0) >= REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
85	}
86	
87	function reimbursementFor(damage: Damage, items: Item[]): number {
88	  const matchingItem = items.find((item) => item.type === damage.type);
89	  if (matchingItem && hasReducedReimbursement(matchingItem)) {
90	    return damage.amount * REDUCED_REIMBURSEMENT_RATE;
91	  }
92	  return damage.amount;
93	}
94	
95	function handleClaim(scenario: any): { payout: number; remainingCap: number } {
96	  const damages: Damage[] = scenario.damages ?? [];
97	  const items: Item[] = scenario.items ?? [];
98	  const reimbursementTotal = damages.reduce(
99	    (sum, d) => sum + reimbursementFor(d, items),
100	    0,
101	  );
102	  const payout = reimbursementTotal - CLAIM_DEDUCTIBLE;
103	  const cap = insuranceCapFor(items);
104	  return { payout, remainingCap: cap - payout };
105	}
106	
107	function handleQuote(scenario: any): { premium: number } {
108	  const items: Item[] = scenario.items ?? [];
109	  const countsByType: Record<string, number> = {};
110	  let surchargesTotal = 0;
111	  let baseTotal = 0;
112	  for (const item of items) {
113	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
114	    surchargesTotal += surchargeForItem(item);
115	    baseTotal += BASE_PREMIUM_BY_ITEM_TYPE[item.type];
116	  }
117	  let itemsTotal = 0;
118	  for (const type of Object.keys(countsByType)) {
119	    itemsTotal += premiumForTypeGroup(type, countsByType[type]);
120	  }
121	  const yearsInsured = scenario.customer?.yearsInsured ?? 0;
122	  const contractNumber = scenario.customer?.contractNumber ?? 1;
123	  const loyaltyDiscount = loyaltyDiscountFor(yearsInsured, baseTotal);
124	  const followUpDiscount = followUpDiscountFor(contractNumber, baseTotal);
125	  return {
126	    premium: Math.ceil(itemsTotal + surchargesTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE),
127	  };
128	}
129	
130	export function runScenario(scenario: any): unknown {
131	  if (scenario.command === "claim") {
132	    return handleClaim(scenario);
133	  }
134	  return handleQuote(scenario);
135	}
